const styles = {
  root: {
    display: 'flex',
    alignItems: 'center',
    borderRadius: '1px',
    height: '40px',
    width: {
      xs: '200px',
      md: '400px'
    }
  },
  input: {
    paddingLeft: '5px',
    width: '100%'
  },
  iconButton: {
    padding: '12px'
  },
  list: {
    fontSize: '0.6rem',
    width: '100%',
    display: 'flex'
  },
  menuBox: {},
  paper: {
    maxHeight: '300px',
    overflowY: 'auto',
    width: {
      xs: '200px',
      md: '400px'
    }
  }
}

export default styles
